	function SkinCloner__cloner_menu_Class(item, parentScope, ggParent, parameter) {
		var me=this;
		var hs='';
		me.parentScope=parentScope;
		me.ggParent=ggParent;
		me.findElements=skin.findElements;
		me.ggIndex=parameter.index;
		me.ggTag = item['tag'];
		me.ggTitle = item['title'];
		me.ggDescription = item['description'];
		me.ggNodeCount = item['nodecount'];
		me.ggNodeId=item['firstnode'];
		let nodeId=item['firstnode'];
		me.ggUserdata=skin.player.getNodeUserdata(me.ggNodeId);
		me.ggUserdata.nodeid=me.ggNodeId;
		me.elementMouseDown={};
		me.elementMouseOver={};
			me.__div=document.createElement('div');
			me.__div.setAttribute('style','visibility: inherit; overflow: visible;');
			me.__div.style.position='absolute';
			me.__div.style.left=parameter.left;
			me.__div.style.top=parameter.top;
			me.__div.style.width='';
			me.__div.style.height='';
			me.__div.style.width=parameter.width;
			me.__div.style.height=parameter.height;
			me.__div.ggIsActive = function() {
				var tags = player.userdata.tags;
				if (tags.indexOf(me.ggTag) == -1) return false;
				for(var i=0;i<me.ggParent.ggCurrentFilter.length;i++) {
					if (tags.indexOf(me.ggParent.ggCurrentFilter[i])==-1) return false;
				}
				return true;
			}
			me.__div.ggElementNodeId=function() {
				return me.ggNodeId;
			}
		el=me._text_button=document.createElement('div');
		el.isDragging = function() {
			let scrollerParent = me._text_button;
			while ((scrollerParent = scrollerParent.parentNode) != null) {
				if (scrollerParent.hasOwnProperty('ggIsDragging') && scrollerParent.ggIsDragging == true) return true;
			}
			return false;
		}
		els=me._text_button__text=document.createElement('div');
		el.className='ggskin ggskin_textdiv';
		el.ggTextDiv=els;
		el.ggId="Text button";
		el.ggParameter={ rx:0,ry:0,a:0,sx:1,sy:1,def:'' };
		el.ggVisible=true;
		el.className="ggskin ggskin_text ";
		el.ggType='text';
		hs ='';
		hs+='border : 0px solid #000000;';
		hs+='color : rgba(255,255,255,1);';
		hs+='height : 85%;';
		hs+='left : 0px;';
		hs+='position : absolute;';
		hs+='top : 0px;';
		hs+='visibility : inherit;';
		hs+='width : 100%;';
		hs+='pointer-events:auto;';
		el.setAttribute('style',hs);
		el.style.transformOrigin='50% 50%';
		hs ='';
		hs += 'box-sizing: border-box;';
		hs+='width: 100%;';
		hs+='height: 100%;';
		hs+='font-size: 16px;';
		hs+='font-weight: inherit;';
		hs+='text-align: left;';
		hs+='white-space: nowrap;';
		hs+='padding: 0px;';
		hs+='overflow: hidden;';
		hs+='text-overflow: ellipsis;';
		els.setAttribute('style',hs);
		me._text_button.ggUpdateText=function() {
			var params = [];
			params.push(player._(String(me.ggTitle)));
			var hs = player._("%1", params);
			if (hs!=this.ggText) {
				this.ggText=hs;
				this.ggTextDiv.innerHTML=hs;
				if (this.ggUpdatePosition) this.ggUpdatePosition();
			}
		}
		me._text_button.ggUpdateText();
		player.addListener('clonerchanged', function() {
			me._text_button.ggUpdateText();
		});
		el.appendChild(els);
		me._text_button.ggIsActive=function() {
			if ((this.parentNode) && (this.parentNode.ggIsActive)) {
				return this.parentNode.ggIsActive();
			}
			return false;
		}
		el.ggElementNodeId=function() {
			if ((this.parentNode) && (this.parentNode.ggElementNodeId)) {
				return this.parentNode.ggElementNodeId();
			}
			return player.getCurrentNode();
		}
		me._text_button.logicBlock_textcolor = function() {
			var newLogicStateTextColor;
			if (
				((me.elementMouseOver['text_button'] == true))
			)
			{
				newLogicStateTextColor = 0;
			}
			else {
				newLogicStateTextColor = -1;
			}
			if (me._text_button.ggCurrentLogicStateTextColor != newLogicStateTextColor) {
				me._text_button.ggCurrentLogicStateTextColor = newLogicStateTextColor;
				me._text_button.style.transition='color 0s';
				if (me._text_button.ggCurrentLogicStateTextColor == 0) {
					me._text_button.style.color="rgba(194,232,18,1)";
				}
				else {
					me._text_button.style.color="rgba(255,255,255,1)";
				}
			}
		}
		me._text_button.logicBlock_textcolor();
		me._text_button.onclick=function (e) {
			if (me._text_button.isDragging()) return;
			player.setVariableValue('var_html_path', me.ggDescription);
			player.setVariableValue('var_show_iframe', true);
			player.setVariableValue('vis_info_btn', false);
			player.setVariableValue('vis_ent_btn', false);
			player.setVariableValue('vis_food_btn', false);
			player.setVariableValue('vis_lang_btn', false);
		}
		me._text_button.onmouseenter=function (e) {
			me.elementMouseOver['text_button']=true;
			me._text_button.logicBlock_textcolor();
		}
		me._text_button.onmouseleave=function (e) {
			me.elementMouseOver['text_button']=false;
			me._text_button.logicBlock_textcolor();
		}
		me._text_button.ggUpdatePosition=function (useTransition) {
		}
		me.__div.appendChild(me._text_button);
		me._text_button.logicBlock_textcolor();
		me.elementMouseOver['text_button']=false;
	};
